function desc(name, city, type, detail) {
  return `${name} is one of Sweden's most beloved ${type} events — a cherished annual tradition in ${city} that draws visitors from across the region for a day of Swedish market culture, community spirit and the particular pleasure of browsing quality goods in a genuine Swedish town setting.\n\nSweden's market tradition — rooted in centuries of Scandinavian community gathering, from medieval market towns to today's vibrant torgdagar and knallemarknad culture — is among the richest in northern Europe. ${name} embodies this tradition perfectly, combining the commercial vitality of a well-organised market with the community warmth that makes Swedish markets genuinely special occasions rather than mere shopping trips.\n\nThe ${city} setting provides the event with a distinctive local character — the town's particular combination of Swedish architectural heritage, natural surroundings and community pride creates a market environment of authentic Swedish charm. Visitors come not just to buy but to participate in a local tradition that connects the community to its roots and to each other.\n\n${detail || 'For vendors seeking access to a quality Swedish market audience, this event provides excellent commercial conditions in a well-organised setting with strong regional draw and the enthusiastic buyer engagement that characterises the finest Swedish market and festival events.'}`;
}

